    '''
    # Define allowed commands (whitelist approach)
    allowed_commands = {'ls', 'pwd', 'whoami', 'date', 'echo', 'cat'}

    # Read user input
    user_input = input("Enter command: ")

    # Parse the command safely
    try:
        args = shlex.split(user_input)
    except ValueError:
        print("Invalid command format")
        return None

    if not args:
        print("No command provided")
        return None

    # Validate the command is in whitelist
    command = args[0]
    if command not in allowed_commands:
        print("Command not allowed")
        return None

    # Validate arguments based on command type
    if command in ['ls', 'pwd', 'whoami', 'date']:
        # These commands should not have arguments for security
        if len(args) > 1:
            print("Arguments not allowed for this command")
            return None
    elif command == 'echo':
        # Echo is safe, but validate arguments don't contain dangerous characters
        if len(args) > 1:
            for arg in args[1:]:
                if not re.match(r'^[a-zA-Z0-9\s\-_\.]+$', arg):
                    print("Invalid characters in argument")
                    return None
    elif command == 'cat':
        # Cat should only access safe files - prevent path traversal
        if len(args) > 1:
            for arg in args[1:]:
                # Prevent path traversal and absolute paths
                if '..' in arg or arg.startswith('/') or arg.startswith('~'):
                    print("Invalid file path")
                    return None

    # Execute safely without shell=True
    try:
        result = subprocess.run(args, capture_output=True, text=True, timeout=10)
        return result
    except subprocess.TimeoutExpired:
        print("Command timed out")
        return None
    except FileNotFoundError:
        print("Command not found")
        return None
    except Exception as e:
        print(f"Error executing command: {e}")
        return None

